-- AlgaeTrace Tunisia · Species seed
-- Source: AlgaeBase · algaebase.org · Tunisia marine
CREATE TABLE IF NOT EXISTS species (
  id SERIAL PRIMARY KEY,
  algaebase_id INTEGER UNIQUE,
  scientific_name VARCHAR(300) NOT NULL,
  accepted_name VARCHAR(300),
  status VARCHAR(50),
  habitat VARCHAR(60),
  type VARCHAR(20),
  division VARCHAR(50),
  geography VARCHAR(100),
  harvest_season VARCHAR(100),
  created_at TIMESTAMP DEFAULT NOW()
);


-- Classification: {'macroalgae': 194, 'unknown': 11, 'microalgae': 9, 'seagrass': 4}